        elif predicate == "demonym":
            details.append(f"whose people are called {obj}")
        elif predicate == "capital":
            details.append(f"has {obj} as its capital")
        else:
            # For leader, mayor, capital - use more natural phrasing
            if predicate in ["leader", "mayor", "capital", "owner"]:
                details.append(f"has {obj} as its {predicate}")
            elif predicate in ["locationIdentifier", "icaoLocationIdentifier", "iataLocationIdentifier"]:
                details.append(f"{predicate.replace('LocationIdentifier', ' identifier').replace('Icao', 'ICAO').replace('Iata', 'IATA')} is {obj}")
            else:
                # Use more natural phrasing for other cases
                normalized_pred = predicate.replace('1stRunway', 'first runway').replace('2ndRunway', 'second runway').replace('3rdRunway', 'third runway').replace('4thRunway', 'fourth runway').replace('5thRunway', 'fifth runway').replace('Length', ' length').replace('SurfaceType', ' surface type').replace('AboveTheSeaLevel', ' above sea level').replace('LocationIdentifier', ' identifier').replace('Iata', 'IATA').replace('Icao', 'ICAO')
                if "runway" in predicate or "elevation" in predicate:
                    details.append(f"has {normalized_pred} of {obj}")
                else:
                    # Use "is" construction where appropriate for better fluency
                    if predicate in ["leader", "mayor", "capital", "owner", "demonym"]:
                        details.append(f"is {obj}")
                    else:
                        details.append(f"has a {normalized_pred} of {obj}")

    # Combine all details into one sentence
    if details:
        result = f"{subject} " + ", ".join(details)
    else:
        result = subject

    return result + "."

